def apply_patch(document, patches):
    """Apply a list of JSON Patch operations (RFC 6902 subset) to a document.
    Supports: add, remove, replace operations.
    Path format: '/key/index/nested' (JSON Pointer, RFC 6901)
    Returns the modified document.
    """
    result = copy.deepcopy(document)

    for patch in patches:
        op = patch['op']
        path = patch['path']
        value = patch.get('value')

        # Parse JSON pointer
        if path == "":
            parts = []
        else:
            parts = path[1:].split('/')  # Remove leading slash and split

        # Unescape JSON Pointer tokens (RFC 6901)
        for i, part in enumerate(parts):
            part = part.replace('~1', '/')  # Must be done first
            part = part.replace('~0', '~')  # Must be done second
            parts[i] = part

        # Handle root document operations
        if len(parts) == 0:
            if op == 'replace' or op == 'add':
                result = value
            elif op == 'remove':
                result = None
            continue

        # Navigate to parent
        parent = result
        for part in parts[:-1]:
            if isinstance(parent, list):
                parent = parent[int(part)]
            else:
                parent = parent[part]

        target = parts[-1]

        # Apply operation
        if op == 'add':
            if isinstance(parent, list):
                if target == '-':
                    parent.append(value)
                else:
                    parent.insert(int(target), value)
            else:
                parent[target] = value

        elif op == 'remove':
            if isinstance(parent, list):
                del parent[int(target)]
            else:
                del parent[target]

        elif op == 'replace':
            if isinstance(parent, list):
                parent[int(target)] = value
            else:
                parent[target] = value

    return result

