        """Delete a word from the trie."""
        if word not in self._words:
            return False

        # Remove from word list
        self._words.remove(word)

        # Delete from trie structure
        self._delete(self, word, 0)
        return True

    def _delete(self, node, word, index):
        """Recursively delete word and clean up empty nodes."""
        if index == len(word):
            node.is_end = False
            # Return True if this node should be deleted (no children and not end of another word)
            return len(node.children) == 0 and not node.is_end

        ch = word[index]
        if ch not in node.children:
            return False

        child_node = node.children[ch]
        should_delete_child = self._delete(child_node, word, index + 1)

        if should_delete_child:
            del node.children[ch]

        # Return True if this node should be deleted
        return len(node.children) == 0 and not node.is_end and node != self

