    def __init__(self):
        self._listeners = {}  # event_name -> list of callbacks

    def on(self, event, callback):
        """Register a listener for an event."""
        if event not in self._listeners:
            self._listeners[event] = []
        self._listeners[event].append(callback)

    def off(self, event, callback):
        """Remove a listener for an event."""
        if event in self._listeners:
            try:
                self._listeners[event].remove(callback)
            except ValueError:
                pass  # Callback not found, ignore

    def emit(self, event, *args, **kwargs):
        """Emit an event, calling all registered listeners."""
        if event not in self._listeners:
            return
        # Create a copy of the listeners list to avoid iterator invalidation
        listeners_copy = self._listeners[event][:]
        for listener in listeners_copy:
            # Check if listener is still in the original list before calling
            if listener in self._listeners[event]:
                listener(*args, **kwargs)

    def listener_count(self, event):
        """Return number of listeners for an event."""
        return len(self._listeners.get(event, []))

