    """Parse a single CSV line into a list of field values.
    Handles quoted fields, escaped quotes (""), and commas inside quotes.
    """
    fields = []
    current = []
    in_quotes = False
    i = 0
    while i < len(line):
        ch = line[i]
        if ch == '"':
            if in_quotes:
                if i + 1 < len(line) and line[i + 1] == '"':
                    # Escaped quote inside quoted field
                    current.append('"')
                    i += 1
                else:
                    # End of quoted field
                    in_quotes = False
            else:
                # Start of quoted field (only if at beginning of field)
                if len(current) == 0:
                    in_quotes = True
                # If current is not empty, this is an invalid quote placement
                # but we'll treat it as a literal quote for robustness
        elif ch == ',' and not in_quotes:
            fields.append(''.join(current))
            current = []
        elif ch == '\n' and not in_quotes:
            break
        else:
            current.append(ch)
        i += 1
    fields.append(''.join(current))
    return fields

