        """Match a path to a handler. Returns (handler, params_dict) or None.
        Static segments take priority over parameterized ones.
        More specific routes (more static segments) take priority.
        """
        if not path:
            path = '/'

        path_parts = path.strip('/').split('/') if path.strip('/') else ['']

        best_match = None
        best_params = None
        best_score = -1

        for route_parts, handler in self.routes:
            if len(route_parts) != len(path_parts):
                continue

            params = {}
            match = True
            static_count = 0

            for rp, pp in zip(route_parts, path_parts):
                if rp.startswith('{') and rp.endswith('}'):
                    param_name = rp[1:-1]
                    params[param_name] = pp
                elif rp == pp:
                    static_count += 1
                else:
                    match = False
                    break

            if match:
                # Score based on number of static segments
                # Higher score = more static segments = more specific
                score = static_count

                if score > best_score:
                    best_match = handler
                    best_params = params
                    best_score = score

        if best_match is not None:
            return (best_match, best_params)
        return None

