    def __init__(self):
        self.routes = []

    def add_route(self, pattern, handler):
        """Add a route pattern like '/users/{id}' mapped to a handler string."""
        parts = pattern.strip('/').split('/')
        self.routes.append((parts, handler))

    def match(self, path):
        """Match a path to a handler. Returns (handler, params_dict) or None.
        Static segments take priority over parameterized ones.
        More specific routes (more static segments) take priority.
        """
        path_parts = path.strip('/').split('/')
        matches = []

        for route_parts, handler in self.routes:
            if len(route_parts) != len(path_parts):
                continue

            params = {}
            match = True
            static_count = 0

            for rp, pp in zip(route_parts, path_parts):
                if rp.startswith('{') and rp.endswith('}'):
                    param_name = rp[1:-1]
                    params[param_name] = pp
                elif rp == pp:
                    static_count += 1
                else:
                    match = False
                    break

            if match:
                # Create a score tuple: (static_segments_count, route_parts_for_tiebreaker)
                # Higher static count wins, and for ties we can add more criteria
                score = (static_count, route_parts)
                matches.append((score, handler, params))

        if not matches:
            return None

        # Sort by score descending - more static segments win
        # For ties, the route_parts comparison will ensure consistent ordering
        matches.sort(key=lambda x: (x[0][0], [-1 if part.startswith('{') else 1 for part in x[0][1]]), reverse=True)

