    """
    def _expand_braces(pattern):
        """Expand brace expressions and return list of expanded patterns."""
        # Find first '{'
        start = pattern.find('{')
        if start == -1:
            return [pattern]

        # Find matching '}' by counting braces
        brace_count = 0
        end = -1
        for i in range(start, len(pattern)):
            if pattern[i] == '{':
                brace_count += 1
            elif pattern[i] == '}':
                brace_count -= 1
                if brace_count == 0:
                    end = i
                    break

        if end == -1:
            return [pattern]

        prefix = pattern[:start]
        suffix = pattern[end + 1:]

        # Split alternatives, respecting nested braces
        alternatives = []
        current_alt = ""
        brace_count = 0
        for i in range(start + 1, end):
            char = pattern[i]
            if char == ',' and brace_count == 0:
                alternatives.append(current_alt)
                current_alt = ""
            else:
                if char == '{':
                    brace_count += 1
                elif char == '}':
                    brace_count -= 1
                current_alt += char
        alternatives.append(current_alt)

        results = []
        for alt in alternatives:
            for expanded in _expand_braces(prefix + alt + suffix):
                results.append(expanded)
        return results

