class WildcardTrie:
    def __init__(self):
        self.children = {}
        self.is_end = False
        self._words = set()  # Use set to avoid duplicates

    def insert(self, word):
        self._words.add(word)
        node = self
        for ch in word:
            if ch not in node.children:
                node.children[ch] = WildcardTrie()
            node = node.children[ch]
        node.is_end = True

    def search(self, pattern):
        """Search for pattern where '.' matches any character."""
        return self._search(self, pattern, 0)

    def _search(self, node, pattern, index):
        if node is None:
            return False
        if index == len(pattern):
            return node.is_end

        ch = pattern[index]
        if ch == '.':
            # Try each child
            for child_key in node.children:
                if self._search(node.children[child_key], pattern, index + 1):
                    return True
            return False
        else:
            child = node.children.get(ch)
            if child is None:
                return False
            return self._search(child, pattern, index + 1)

    def get_all_words(self):
        """Return all inserted words."""
        return list(self._words)

    def starts_with(self, prefix):
        """Return True if any word starts with the given prefix."""
        node = self
        for ch in prefix:
            if ch not in node.children:
                return False
            node = node.children[ch]
        return self._has_words_in_subtree(node)

    def _has_words_in_subtree(self, node):
        """Check if there are any complete words in this subtree."""
        if node.is_end:
            return True
        for child in node.children.values():
            if self._has_words_in_subtree(child):
                return True
        return False

    def delete(self, word):
        """Delete a word from the trie."""
        if word in self._words:
            self._words.remove(word)
            self._delete(self, word, 0)

    def _delete(self, node, word, index):
        if node is None:
            return False

        if index == len(word):
            # We've reached the end of the word
            if node.is_end:
                node.is_end = False
                # Return True if this node has no children (can be deleted)
                return len(node.children) == 0
            return False

        ch = word[index]
        child_node = node.children.get(ch)
        if child_node is None:
            return False

        # Recursively delete from child
        should_delete_child = self._delete(child_node, word, index + 1)

        # If child should be deleted, remove it
        if should_delete_child:
            del node.children[ch]

        # Return True if this node can be deleted
        # (no children, not end of another word)
        return len(node.children) == 0 and not node.is_end

