                if brace_count == 0:
                    end = i
                    break
            i += 1

        if end == -1:
            return [pattern]

        prefix = pattern[:start]
        suffix = pattern[end + 1:]

        # Parse alternatives, respecting nested braces
        alternatives = []
        current_alt = ""
        brace_count = 0
        i = start + 1

        while i < end:
            if pattern[i] == '\\':
                # Add escaped character as-is
